import { execSync } from 'child_process';

function runGws(cmd: string) {
  const result = execSync(`gws ${cmd} --format json`, { encoding: 'utf8' });
  return JSON.parse(result);
}

function extractEmail(str: string): string {
  const match = str.match(/<([^>]+)>/) || str.match(/([^\s@]+@[^\s@]+\.[^\s@]+)/);
  return match ? match[1] : str.trim();
}

function formatGmailDate(d: Date): string {
  return d.getFullYear() + '/' + String(d.getMonth() + 1).padStart(2, '0') + '/' + String(d.getDate()).padStart(2, '0');
}

function parseMessage(msg: any) {
  const headers: { [key: string]: string } = {};
  msg.payload.headers.forEach((h: any) => {
    headers[h.name.toLowerCase()] = h.value;
  });
  const date = new Date(headers['date']);
  const from = extractEmail(headers['from'] || '');
  const to = headers['to'] || '';
  const isSent = msg.labelIds.includes('SENT');
  const isInbox = msg.labelIds.includes('INBOX');
  return { date, from, to, isSent, isInbox, threadId: msg.threadId, rawTo: to };
}

async function main() {
  const profile = runGws(`gmail users getProfile --params ${JSON.stringify({userId: 'me'})}`);
  const myEmail = profile.emailAddress;

  const endDate = new Date();
  const startDate = new Date();
  startDate.setDate(startDate.getDate() - 30);

  const query = `after:${formatGmailDate(startDate)} before:${formatGmailDate(endDate)}`;
  const threadsList = runGws(`gmail threads list --query "${query}" --params ${JSON.stringify({userId: 'me'})}`);

  const threadMap = new Map<string, any[]>();
  for (const thread of threadsList.threads || []) {
    const threadData = runGws(`gmail threads get --id ${thread.id} --params ${JSON.stringify({userId: 'me'})}`);
    const messages = threadData.messages.map(parseMessage);
    threadMap.set(thread.id, messages);
  }

  const allMessages: any[] = [];
  for (const messages of threadMap.values()) {
    allMessages.push(...messages);
  }

  // Total sent
  const sentMessages = allMessages.filter(m => m.isSent);
  const totalSent = sentMessages.length;

  // Top recipients
  const recipientCount = new Map<string, number>();
  for (const msg of sentMessages) {
    const tos = msg.rawTo.split(',').map((t: string) => extractEmail(t.trim()));
    for (const to of tos) {
      if (to) {
        recipientCount.set(to, (recipientCount.get(to) || 0) + 1);
      }
    }
  }
  const sortedRecipients = Array.from(recipientCount.entries()).sort((a, b) => b[1] - a[1]);
  const topRecipients = sortedRecipients.slice(0, 3).map(([email, count]) => `${email}:${count}`).join(', ');

  // Reply rate
  let repliedCount = 0;
  for (const sent of sentMessages) {
    const threadMsgs = threadMap.get(sent.threadId) || [];
    const hasReply = threadMsgs.some((m: any) => !m.isSent && m.from !== myEmail && m.date > sent.date);
    if (hasReply) repliedCount++;
  }
  const replyRate = totalSent > 0 ? ((repliedCount / totalSent) * 100).toFixed(1) : '0.0';

  // Average response time
  const responseTimes: number[] = [];
  for (const threadMsgs of threadMap.values()) {
    const sortedMsgs = threadMsgs.sort((a, b) => a.date.getTime() - b.date.getTime());
    for (let i = 0; i < sortedMsgs.length; i++) {
      const msg = sortedMsgs[i];
      if (msg.isInbox && !msg.isSent && msg.from !== myEmail) {
        // Find next sent message
        for (let j = i + 1; j < sortedMsgs.length; j++) {
          const nextMsg = sortedMsgs[j];
          if (nextMsg.isSent && nextMsg.from === myEmail) {
            const diffHours = (nextMsg.date.getTime() - msg.date.getTime()) / (1000 * 60 * 60);
            responseTimes.push(diffHours);
            break; // Only the first reply
          }
        }
      }
    }
  }
  const avgResponseTime = responseTimes.length > 0 ? (responseTimes.reduce((a, b) => a + b, 0) / responseTimes.length).toFixed(1) : '0.0';

  console.log(`TotalSent: ${totalSent}`);
  console.log(`TopRecipients: ${topRecipients}`);
  console.log(`ReplyRate: ${replyRate}%`);
  console.log(`AvgResponseTimeHours: ${avgResponseTime}`);
}

main().catch(console.error);

